package core.metamodel.org.apache.isis.core.commons.compare;

public class SequenceCompare { private SequenceCompare ( ) { } public static int compareNullLast ( String sequence1 , String sequence2 ) { if ( sequence1 == null && sequence2 == null ) { return 0 ; } if ( sequence1 == null && sequence2 != null ) { return + 1 ; } if ( sequence1 != null && sequence2 == null ) { return - 1 ; } final String [ ] components1 = componentsFor ( sequence1 ) ; final String [ ] components2 = componentsFor ( sequence2 ) ; final int length1 = components1 . length ; final int length2 = components2 . length ; if ( length1 == 0 && length2 == 0 ) { return 0 ; } int n = 0 ; while ( true ) { final int length = n + 1 ; if ( length1 < length && length2 >= length ) { return - 1 ; } if ( length2 < length && length1 >= length ) { return + 1 ; } if ( length1 < length && length2 < length ) { return 0 ; } int componentCompare = 0 ; try { final Integer c1 = Integer . valueOf ( components1 [ n ] ) ; final Integer c2 = Integer . valueOf ( components2 [ n ] ) ; componentCompare = c1 . compareTo ( c2 ) ; } catch ( final NumberFormatException nfe ) { componentCompare = components1 [ n ] . compareTo ( components2 [ n ] ) ; } if ( componentCompare != 0 ) { return componentCompare ; } n ++ ; } } private static String [ ] componentsFor ( final String sequence ) { final StringTokenizer tokens = new StringTokenizer ( sequence , "." , false ) ; final String [ ] components = new String [ tokens . countTokens ( ) ] ; for ( int i = 0 ; tokens . hasMoreTokens ( ) ; i ++ ) { components [ i ] = tokens . nextToken ( ) ; } return components ; } }